sql:
SELECT distribution_description 
FROM distributions 
WHERE byte_size > (SELECT AVG(byte_size) FROM distributions);

SELECT DISTINCT users.user_name, users.email
FROM users
INNER JOIN dataset_comments ON users.user_id = dataset_comments.user_id;

SELECT DISTINCT d.dataset_name 
FROM datasets d
JOIN dataset_tags t ON d.dataset_id = t.dataset_id;

SELECT datasets.dataset_name, licenses.license_url
FROM datasets
INNER JOIN licenses ON datasets.license_id = licenses.license_id;

SELECT user_name, email 
FROM users 
WHERE role = 'researcher';

SELECT dataset_name 
FROM datasets 
WHERE dataset_id = (
  SELECT MAX(dataset_id) 
  FROM datasets
);

SELECT MIN(upload_date) AS oldest_data_file
FROM data_files
WHERE distribution_id = 0;

SELECT user_name, email, role
FROM users
WHERE user_id = (
    SELECT user_id 
    FROM access_logs
    WHERE access_date = (
        SELECT MAX(access_date) 
        FROM access_logs
    )
);

SELECT datasets.dataset_name, dataset_versions.version_number
FROM datasets
INNER JOIN dataset_versions ON datasets.dataset_id = dataset_versions.dataset_id;

SELECT tag_name, tag_description
FROM dataset_tags
WHERE dataset_id = 3;

external_knowledge:
'researchers' refers to users with the role specified as 'researcher' in the database;
'workplace' refers to the user's institution;
'department' is the specific department within the user's institution.

sql:
SELECT file_id, file_name, file_size
FROM data_files
ORDER BY file_size DESC;

SELECT comment_text, created_at
FROM dataset_comments
WHERE dataset_id = 0 AND comment_id = 0;

external_knowledge:
- 'certain phase in their development' refers to a specific version number of the dataset;
- 'type of data they encompass' relates to the category of the dataset;
- 'organizations behind them' means the provider of the dataset;
- 'terms of use' refers to the license details;
- 'digital identifiers' are the DOIs.
